var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 5","JPN":"CSE Lv.5","ENG":"CSE Lv. 5","TWN":"CSE Lv.5","DEU":"CSE Lv. 5","FRA":"CSE Lv. 5"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is the Administration.</color>","TWN":"<color=#ffd34c>管理局通知。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這是實際情況。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아직 대피하지 못한 시민분들께서는 최대한 방위선 쪽으로 이동하시기 바랍니다.</color>","JPN":"<color=#ffd34c>まだ避難していない市民の皆様は速やかに防衛線の方へ移動してください。</color>","ENG":"<color=#ffd34c>If you have not yet evacuated, proceed toward the defense line.</color>","TWN":"<color=#ffd34c>尚未撤離的市民請盡量向防線方向移動。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>대균열 확산의 여파로 도시 내부에 숨는 것은 추천해 드리지 않습니다.</color>","JPN":"<color=#ffd34c>大亀裂拡散の影響により、都市内部に隠れ留まることは推奨しません。</color>","ENG":"<color=#ffd34c>Due to the spread of the Grand Dimension Crevice, sheltering within the city is not recommended.</color>","TWN":"<color=#ffd34c>由於大峽谷的擴散的餘波，建議不要躲在城市內。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>방위선에서 멀리 떨어진 도심지에 계신 분들은 급성 침식 증후군을 조심하시길 바라며.</color>","JPN":"<color=#ffd34c>防衛線から離れた都市中心部にいる方々は、急性侵食症候群にお気をつけください。</color>","ENG":"<color=#ffd34c>Those far from the defense line, beware of acute Corruption Syndrome.</color>","TWN":"<color=#ffd34c>若身處距離防線較遠市區的市民，請注意急性侵蝕症候群。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>이미 가망이 없다는 판단이 든 분들은 신속하고 편안한 죽음을 선택하시길 바랍니다.</color>","JPN":"<color=#ff3636>すでに手遅れと判断された方は、迅速かつ安楽な死をお選びください。</color>","ENG":"<color=#ff3636>If you judge survival to be impossible, choose a swift and painless death.</color>","TWN":"<color=#ff3636>若已判斷無救治可能，請迅速選擇安樂死亡。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이상, 안내된 지침은 재난경보 해제까지 유효합니다.</color>","JPN":"<color=#ffd34c>以上、ご案内している行動指針は災難警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The broadcast guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>上述內容將維持到災難警報解除為止。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"관측 보고드립니다!","JPN":"観測報告します！","ENG":"Observation report!","TWN":"報告觀測結果！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"현재 뿌리가 뻗는 구역의 CSE 레벨이 급격하게 상승하고 있습니다!","JPN":"現在、根が張っている区域のCSEレベルが急激に上昇中！","ENG":"CSE levels are rapidly rising in the areas the roots are spreading into!","TWN":"目前根部擴散區域的CSE等級急速上升！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"나무뿌리가 계속 도시를 잠식하면……!","JPN":"このまま都市が木の根に覆われてしまったら……！","ENG":"If those roots keep engulfing the city...!","TWN":"如果樹根持續吞噬城市……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"여기는 로터스 ARC-EA2 구역!","JPN":"こちら、ロータスARC-EA2！","ENG":"This is Lotus ARC-EA2!","TWN":"這裡是洛德斯ARC-EA2區！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"급성 침식 재난 발생 중!","JPN":"急性侵食災害が発生中！","ENG":"Acute Corruption Disaster in progress!","TWN":"急性侵蝕災難發生中！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"순식간에 많은 사람들이 침식체로 변했다!","JPN":"大勢の人が、なす術もなく侵食体に変化してしまった！","ENG":"People are turning into C.O.s in an instant!","TWN":"大量人員瞬間變成侵蝕體！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"지원을 요청한다!","JPN":"支援を要請する！","ENG":"Requesting support!","TWN":"請求支援！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"지원을……!","JPN":"支援を……！","ENG":"Reques–!","TWN":"支援……！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"토, 통신이?","JPN":"つ、通信が？","ENG":"Th-the comms?!","TWN":"訊、訊號？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이봐! 들려?! 대답해!","JPN":"ちょっと！　聞こえてる！？　返事して！","ENG":"Hey! Can you hear me?! Answer me!","TWN":"喂！聽得到嗎？回答我！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"침식파 때문에 전파가 교란되고 있는 모양입니다.","JPN":"侵食波のせいでジャミングが起こっているようです。","ENG":"The signal's being scrambled by the Corruption rays.","TWN":"電波因為侵蝕波受到干擾。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우선 여기서 할 수 있는 것들을 하는 것이 우선입니다, 시니어님.","JPN":"今はまず、ここでできることをしましょう、シニア様。","ENG":"For now, we must focus on what we can do here, Senior.","TWN":"目前最重要的是做好能在這裡做的事，Senior。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나도 알아! 하지만 지금 CSE 레벨이 5까지 치솟았잖아!","JPN":"分かってる！　でも、もうCSEレベルが5まで上がってるんだよ！","ENG":"I know! But the CSE Level has hit 5!","TWN":"我知道！但CSE 等級已經飆升到5了！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이, 이러다가 정말 CSE 레벨 6에 도달하면 어쩌지?","JPN":"こ、このままCSEレベルが6に達したらどうしよう？","ENG":"I-if it reaches Level 6, what do we do?","TWN":"再、再這樣下去，真的會達到CSE等級6嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되면 정말 6종 침식체란 녀석이 강림할지도 모른다고!","JPN":"そうなったら、本当に第6種侵食体が降臨するかもしれない！","ENG":"If that happens, a Category 6 C.O. might really descend!","TWN":"那樣的話，說不定6級侵蝕體會降臨！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"사도가 미온적으로 행동한 이유가 이것 때문이었나…….","JPN":"使徒が積極的に動かなかった理由はこれだったか……","ENG":"So that's why the Apostle acted lukewarm...","TWN":"這就是使徒行事不積極的原因嗎……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"마치 뿌리가 영양분을 빨아들이는 것처럼 황폐해지는 것 같군.","JPN":"まるで根に養分を吸われているかのように、荒廃していく。","ENG":"It's draining us like roots siphoning nutrients, leaving desolation.","TWN":"就像根系吸取養分，整個地方陷入荒蕪中。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이건 도대체…….","JPN":"これはいったい……","ENG":"Just what is this...","TWN":"這到底……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으… 이, 이럴 땐 어떻게 해야…….","JPN":"う……こ、こんな時はどうすれば……","ENG":"Ooh... W-what do we even do...?","TWN":" 呃……這、這種情況該怎麼辦……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고뇌에 찬 얼굴이군.","JPN":"困り果てているといった顔だな。","ENG":"That's a face steeped in anguish.","TWN":"妳還真是滿臉煩惱呢。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최, 최고 관리자? 급한 일은 다 끝난 거야?","JPN":"さ、最高管理者？　急用は全部片付いたの？","ENG":"S-Supreme Administrator? Are your urgent matters over?","TWN":"最、最高管理者？緊急的事都結束了嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 르네 양이 무사히 도착해서 그쪽 사정을 말해줬거든.","JPN":"ああ。ルネ君が無事こちらに到着して、事情を説明してくれた。","ENG":"Yes. Renée arrived safely and briefed me.","TWN":"對。芮妮小姐已經平安抵達，告訴我那邊的情況了。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비록 권한은 동결되었지만, 자네의 상사로서 몇 마디 덕담 정도는 해줘야 하지 않겠나?","JPN":"権限が凍結されている身ではあるが、君の上司として労いの言葉はかけてやらねばと思ってね。","ENG":"My authority may be frozen, but as your superior I can still offer a few words.","TWN":"雖然權限被凍結，但身為妳的上司，還是該說幾句安慰的話吧？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 이제 와서 그런 말 해봤자 하나도 도움 안 된다고.","JPN":"ふん、今更そんなこと言っても何の役にも立たないって。","ENG":"Hmph, saying that now doesn't help at all.","TWN":"哼，現在說這種話根本沒用。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 호기심이 왕성한 만큼 인정 욕구가 강해 시니어 자리를 거절할 수 없을 거란 걸 알고 있었네.","JPN":"イゾルデ君は好奇心が旺盛な分、承認欲求も強く、シニアの座を断れないだろうという確信があった。","ENG":"Your curiosity is strong, and so is your need for recognition. I knew you wouldn't refuse the Senior's seat.","TWN":"伊索德小姐好奇心旺盛，也很渴望被認可。所以我早就知道妳不可能拒絕Senior的職位。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 호기심이 왕성하다는 건 이 세상을 발전시킬 가능성이 높다는 것이고,","JPN":"裏を返せば、溢れる好奇心とはすなわち、世界を発展させる可能性の生みの親でもあり、","ENG":"But strong curiosity means a high chance to advance this world,","TWN":"但好奇心旺盛也意味著妳有很大的潛力推動這個世界的發展，"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인정 욕구가 강하다는 것은 책임감과 그에 받쳐주는 리더쉽이 뛰어나다는 걸세.","JPN":"強い承認欲求は、責任感と優れたリーダーシップに繋がるとも捉えられる。","ENG":"and a need for recognition often pairs with responsibility and leadership.","TWN":"而渴望被認同則代表妳有責任感及相應的領導能力。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 자네를 시니어 자리에 앉힌 건 잘한 선택이었어.","JPN":"やはり、君をシニアの座に就かせて正解だった。","ENG":"Appointing you Senior was the right choice.","TWN":"果然把妳安排到Senior的位置是正確的選擇。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L7_1","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L7_1","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"L30_1","JPN":"L30_1","ENG":"L30_1","TWN":"L30_1","DEU":"L30_1","FRA":"L30_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};